@@ -2146,6 +2147,11 @@ var annotationLabelHandler = (function () {
             return;
         }

+        // Update label if parent is a measurement annotation since its value could have changed
+        if (annotation.isMeasurementAnnotation()) {
+            updateLabelInternal(annotation, labelAnnotation);
+        }
+
         const labelColors = getLabelColorAndStrike(annotation);
         if (!labelColors) {
             return;
@@ -2159,44 +2165,6 @@ var annotationLabelHandler = (function () {
         m_annotationManager.redrawAnnotation(labelAnnotation);
     }

-    m_Exports.closeLabelStylePopup = closeLabelStylePopup;
-    /**
-     * @description close the label style popup for the annotation
-     * @param {any} annotation the annotation object
-     * @return void
-     * */
-    function closeLabelStylePopup(annotation) {
-        // Exceptions are handled by the caller
-
-        // there is no direct method to close the label style popup, so we need to blur the editor
-        // this is a workaround to close the style popup for the label annotation
-        function hidePdftronStylePopup() {
-            // a recursive function to hide the pdftron style popup, it will try to hide the popup 3 times
-
-            editor.blur(); // blur the editor to close the style popup
-            m_annotationManager.deselectAnnotation(annotation);
-            // we need to repeat this since the UI may have a delay to hide the popup
-            counter < 3 && setTimeout(hidePdftronStylePopup, 10);
-            counter++;
-            if (counter === 3) {
-                // double clicking free-text annotation may increase the text size (possible Apryse bug), this is a workaround to keep label content not overflowing
-                const document = m_documentViewer.getDocument();
-                fitTextInLabel(annotation, document.getPageInfo(1), document.getPageMatrix(1), document.getPageRotation(1));
-            }
-        }
-
-        // counter for hiding the pdftron style popup
-        let counter = 0;
-        // get the style editor for this annotation
-        const editor = annotation.getEditor();
-
-        if (editor) {
-            // if the annotation is a label with editor, don't open style dialog
-            setTimeout(hidePdftronStylePopup);
-        }
-    }
-
-
     m_Exports.updateLabelText = updateLabelText;

     /**
@@ -2212,10 +2180,19 @@ var annotationLabelHandler = (function () {
             return;
         }

-        labelAnnotation.setContents(getLabelText(annotation, annotation.isMeasurementAnnotation()));
+        updateLabelInternal(annotation, labelAnnotation);
+        m_annotationManager.redrawAnnotation(labelAnnotation);
+    }
+
+    /**
+     * @description helper to update label contents and adjust label size after annotation link/measurement is edited
+     * @param {any} parentAnnotation the annotation which has a label
+     * @param {any} labelAnnotation the label annotation with content that needs to be updated
+     */
+    function updateLabelInternal(parentAnnotation, labelAnnotation) {
+        labelAnnotation.setContents(getLabelText(parentAnnotation, parentAnnotation.isMeasurementAnnotation()));
         const document = m_documentViewer.getDocument();
         fitTextInLabel(labelAnnotation, document.getPageInfo(1), document.getPageMatrix(1), document.getPageRotation(1));
-        m_annotationManager.redrawAnnotation(labelAnnotation);
     }

     // return the exports

